import json
from jsonschema import validate, ValidationError

# --- Layer 1: Grounded prompt construction ---
def build_grounded_prompt(user_query: str, retrieved_docs: list[dict]) -> str:
    context_block = "\n".join(
        f"[Source {i+1}]: {doc['text']}" for i, doc in enumerate(retrieved_docs)
    )
    return f"""Use ONLY the sources below to answer. Cite [Source N] for every fact.
If the answer is not present in the sources, say 'I cannot determine this from the provided context.'

Sources:
{context_block}

Query: {user_query}"""

# --- Layer 2: Structured output schema ---
ACTION_SCHEMA = {
    "type": "object",
    "properties": {
        "action": {"type": "string", "enum": ["create_order", "cancel_order", "fetch_status"]},
        "order_id": {"type": "string", "pattern": "^ORD-[0-9]{6}$"},
        "amount_cents": {"type": "integer", "minimum": 0, "maximum": 1_000_000},
        "reasoning": {"type": "string", "minLength": 10}
    },
    "required": ["action", "reasoning"],
    "additionalProperties": False
}

# --- Layer 3: Semantic validation ---
def validate_action(parsed: dict, db) -> tuple[bool, str]:
    if "order_id" in parsed:
        if not db.order_exists(parsed["order_id"]):
            return False, f"Order {parsed['order_id']} does not exist"
    if parsed.get("action") == "cancel_order":
        order = db.get_order(parsed["order_id"])
        if order["status"] not in ("pending", "processing"):
            return False, f"Cannot cancel order in status '{order['status']}'"
    return True, "ok"

# --- Orchestration ---
def run_agent_action(user_query: str, retrieved_docs: list[dict], db, llm_client):
    prompt = build_grounded_prompt(user_query, retrieved_docs)

    raw = llm_client.chat(
        model="claude-opus-4-5",
        messages=[{"role": "user", "content": prompt}],
        response_format={"type": "json_object"},   # Layer 2
    )

    try:
        parsed = json.loads(raw)
        validate(instance=parsed, schema=ACTION_SCHEMA)  # Layer 2 schema check
    except (json.JSONDecodeError, ValidationError) as e:
        raise ValueError(f"Structural hallucination detected: {e}") from e

    ok, reason = validate_action(parsed, db)           # Layer 3
    if not ok:
        raise ValueError(f"Semantic validation failed: {reason}")

    # Layer 4: high-risk actions require human approval
    if parsed["action"] == "cancel_order":
        approval = db.request_human_approval(parsed)
        if not approval.approved:
            raise PermissionError("Human reviewer rejected this action")

    return db.execute(parsed)

from pydantic import BaseModel, field_validator
from enum import Enum
import anthropic, json

class Cabin(str, Enum):
    economy = "economy"
    business = "business"
    first = "first"

class FlightBooking(BaseModel):
    origin: str        # IATA airport code, e.g. "LHR"
    destination: str
    cabin: Cabin
    passengers: int

    @field_validator("origin", "destination")
    @classmethod
    def must_be_iata(cls, v: str) -> str:
        if len(v) != 3 or not v.isalpha():
            raise ValueError(f"Expected 3-letter IATA code, got '{v}'")
        return v.upper()

    @field_validator("passengers")
    @classmethod
    def must_be_positive(cls, v: int) -> int:
        if v < 1 or v > 9:
            raise ValueError(f"passengers must be 1-9, got {v}")
        return v

client = anthropic.Anthropic()

def book_flight(user_input: str) -> FlightBooking:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        system=(
            "Extract a flight booking from the user message. "
            "Reply with valid JSON only: {origin, destination, cabin, passengers}. "
            "Use 3-letter IATA codes. cabin must be economy|business|first."
        ),
        messages=[{"role": "user", "content": user_input}],
    )
    text = resp.content[0].text.strip()
    try:
        data = json.loads(text)
    except json.JSONDecodeError as e:
        raise ValueError(f"Model returned non-JSON: {text!r}") from e

    return FlightBooking(**data)  # ValidationError if hallucinated shape/values

# Try it:
try:
    booking = book_flight("I need 2 economy seats from London Heathrow to JFK")
    print(booking)
    # FlightBooking(origin='LHR', destination='JFK', cabin=<Cabin.economy>, passengers=2)
except Exception as e:
    print(f"Validation failed (hallucination caught): {e}")
